var e=JSON.parse(`[{"id":"L3_1","type":"narration","speaker":null,"text":{"KOREA":"오래 전, 아홉 대륙을 아우르는 전설이 있었다.","JPN":"大昔、九つの大陸をまとめる伝説があった。","ENG":"A long time ago, there was a legend that was told across the nine continents.","TWN":"這無趣的傳說是這麼說的，很久很久以前，據說9個大陸是合在一起的。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"narration","speaker":null,"text":{"KOREA":"하늘의 선택을 받은 구원자가 나타나 모두를 괴로움에서 구원하리라는, 시시한 전설이.","JPN":"天から選ばれし救世主が現れ、みんなを苦痛から救うというくだらない伝説が。","ENG":"A bland legend that spoke of the arrival of the Savior, appointed by the heavens, who would save everyone from suffering.","TWN":"天選之救贖者出現，將在水深火熱之中的人救贖出來。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"narration","speaker":null,"text":{"KOREA":"그는 어두운 시대에 희망을 추구하던 여인 앞에 홀연히 나타나 성녀를 찾아왔다고 하지만…","JPN":"彼は暗き時代の中で希望を求めていた女性の前に忽然と現れ、聖女の力が必要だという。だけど……","ENG":"It is said that he would reveal himself to a woman praying for hope in a dark age and claim that he came searching for the Saintess, but...","TWN":"女孩則是在黑暗的世代中尋求一絲希望，有一天，救贖者突然出現在女孩面前，說是來找聖女的…"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"narration","speaker":null,"text":{"KOREA":"당시 노예였던 내게, 그것은 너무나도 먼 세계의 이야기였다.","JPN":"当時奴隷だった私にとって、それはあまりにも遠い世界の話だった。","ENG":"It was such a distant story, as I was a slave at the time.","TWN":"但對於當時身為奴隸的我而言，這是一個遙不可及的故事。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":"GRANDPA_MEMORIAL_NULL","text":{"KOREA":"쿨럭. 쿨럭…!","JPN":"ゴホッ。ゴホッ……！","ENG":"*Cough!* *Cough!*","TWN":"咳咳，咳咳…！"},"stage":{"bg":"PRISON_NIGHT_02","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_PAST_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"HOLY_KNIGHT_PAST_NULL","text":{"KOREA":"할아버지. 몸은 좀 괜찮으세요?","JPN":"お爺さん。体の具合はどう？","ENG":"Grandfather. Are you okay?","TWN":"爺爺，你還好嗎？"},"stage":{"bg":"PRISON_NIGHT_02","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_PAST_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"HOLY_KNIGHT_PAST_NULL","text":{"KOREA":"자요. 주인 녀석 모르게 물을 가져왔어요. 이것 좀 드시고 하세요.","JPN":"はい。主人のやつには内緒で水を持ってきたよ。飲んで。","ENG":"Here. I brought you some water behind the master's back. Please, drink some.","TWN":"這是我從堂主那偷拿來的水，爺爺你喝一點吧。"},"stage":{"bg":"PRISON_NIGHT_02","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_PAST_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"GRANDPA_MEMORIAL_NULL","text":{"KOREA":"고맙구나. 루크야… 쿨럭!","JPN":"ありがとう。ルク……ゴホッ！","ENG":"Thank you, Lucy... *Cough!*","TWN":"謝謝你，露可… 咳咳！"},"stage":{"bg":"PRISON_NIGHT_02","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_PAST_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"HOLY_KNIGHT_PAST_NULL","text":{"KOREA":"그러게 몸도 안 좋으신 분이 뭘 또 그렇게 무리하시고 그래요.","JPN":"具合もよくないんだから無理しなきゃいいのに。","ENG":"You know you're unwell. You shouldn't overwork yourself.","TWN":"你身體又不好，幹嘛這樣勉強自己。"},"stage":{"bg":"PRISON_NIGHT_02","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_PAST_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"HOLY_KNIGHT_PAST_NULL","text":{"KOREA":"할아버지가 다치면 저희만 힘들어져요. 저는 어제 맞은 데가 아직도 욱신거린다고요.","JPN":"お爺さんが怪我したら私たちが苦労するんだよ。私なんか昨日叩かれたところがまだ痛いんだから。","ENG":"If you hurt yourself, we're the ones who will suffer. It still hurts where I got hit yesterday.","TWN":"爺爺受傷的話，辛苦的只有我們。我昨天挨的那一頓打，到現在還會痛呢。"},"stage":{"bg":"PRISON_NIGHT_02","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_PAST_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"GRANDPA_MEMORIAL_NULL","text":{"KOREA":"루크야… 넌 이 할애비를 원망하니?","JPN":"ルク……わしを恨んでるかい？","ENG":"Lucy... Do you hate this old man?","TWN":"露可… 你會怨恨爺爺嗎？"},"stage":{"bg":"PRISON_NIGHT_02","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_PAST_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"GRANDPA_MEMORIAL_NULL","text":{"KOREA":"조금만 참아주려무나. 구원자님께서 곧 우리를 구원해주실… 쿨럭!","JPN":"もう少し我慢しておくれ。救世主様がすぐ、我々を救って……ゴホッ！","ENG":"It won't be much longer. The Savior will come to save– *Cough!*","TWN":"再忍耐一下，救贖者大人很快就會來拯救我們… 咳咳！"},"stage":{"bg":"PRISON_NIGHT_02","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_PAST_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"HOLY_KNIGHT_PAST_NULL","text":{"KOREA":"그놈의 구원이니 뭐니…! 이제 제발 정신 좀 차려요!","JPN":"救世だのなんの……！　もういいかげん目を覚ましてよ！","ENG":"Stop it with the Savior gibberish! Please, you have to come to your senses!","TWN":"那所謂的救贖…！我拜託你清醒一點！"},"stage":{"bg":"PRISON_NIGHT_02","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_PAST_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"HOLY_KNIGHT_PAST_NULL","text":{"KOREA":"할아버지도 아시잖아요! 제국에서 정한 구원자는 저희 같은 노예에게 아무런 관심도 없다고요!","JPN":"お爺さんもわかってるでしょ！　帝国が決めた救世主は、私たちみたいな奴隷にはなんの興味もないって！","ENG":"You know that the Savior appointed by the Empire isn't interested in slaves like us!","TWN":"爺爺你也知道！帝國指定的救贖者大人根本就不關心我們這些奴隸！"},"stage":{"bg":"PRISON_NIGHT_02","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_PAST_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"HOLY_KNIGHT_PAST_NULL","text":{"KOREA":"그러니까 제발……","JPN":"だから、お願い……","ENG":"So please...","TWN":"所以我拜託你…"},"stage":{"bg":"PRISON_NIGHT_02","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_PAST_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"HOLY_KNIGHT_PAST_NULL","text":{"KOREA":"제발… 정신 좀 차리라고요…….","JPN":"頼むから……目を覚まして……","ENG":"Please... come to your senses...","TWN":"拜託你…醒醒吧…"},"stage":{"bg":"PRISON_NIGHT_02","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_PAST_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L26_1","type":"narration","speaker":null,"text":{"KOREA":"지독하리만큼 편협한 이야기임에도,\\n눈을 감으면 펼쳐지는 광명이 현실의 어둠마저 걷어 내주기 때문일까.","JPN":"何の根拠もない話なのに、目を閉じると広がる光明が現実の闇さえ晴らしてくれるからだろうか。","ENG":"It was such a closed-minded story, but perhaps the brilliant light that shined on him when he closed his eyes chased away the darkness in reality.","TWN":"雖然這是一個狹隘至極的故事，\\n但每當閉上眼睛時，那光明就會展現在眼前，甚至能驅散現實的黑暗。"},"stage":{"bg":"PRISON_NIGHT_02","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_PAST_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"GRANDPA_MEMORIAL_NULL","text":{"KOREA":"구원자님… 부디…","JPN":"救世主様……どうか……","ENG":"Savior... please...","TWN":"救贖者大人… 求求你…"},"stage":{"bg":"PRISON_NIGHT_02","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_PAST_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"GRANDPA_MEMORIAL_NULL","text":{"KOREA":"구원… 하소서…….","JPN":"お救い……くださいませ……","ENG":"Save... us...","TWN":"拯救我們吧…"},"stage":{"bg":"PRISON_NIGHT_02","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_PAST_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"narration","speaker":null,"text":{"KOREA":"그것이 분에 넘친 기대라는 것을 알고 있음에도,\\n할아버지는 죽는 그 순간까지 희망을 놓지 않았다.","JPN":"それが出過ぎた期待であることとわかっていながら、お爺さんは死ぬ間際まで希望を手放さなかった。","ENG":"He knew his hopes were far-fetched, but he did not let them go, even on his deathbed.","TWN":"即使心裡明白這是個不切實際的期待，\\n但爺爺直到死去的那一刻都沒有放棄希望。"},"stage":{"bg":"PRISON_NIGHT_02","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_PAST_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":null,"text":{"KOREA":"그래.","JPN":"そう。","ENG":"Yes.","TWN":"沒錯。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L34_1","type":"dialog","speaker":null,"text":{"KOREA":"기다리기만 해선……","JPN":"待つだけでは……","ENG":"Waiting...","TWN":"光是等待……"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L37_1","type":"dialog","speaker":"HOLY_MEMORIAL_NPC_NULL","text":{"KOREA":"<color=#ff3636>아무것도 바뀌지 않아</color>.","JPN":"<color=#ff3636>何も変わらない</color>。","ENG":"<color=#ff3636>won't get you anywhere</color>.","TWN":"<color=#ff3636>什麼事都不會改變的</color>。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":null,"C":{"char_id":"HOLY_MEMORIAL_NPC_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L40_1","type":"subtitle","speaker":null,"text":{"KOREA":"<color=#ffd34c>아르카데나 제국</color> 수도. 센트럴 팰리스.","JPN":"<color=#ffd34c>アルカデナ帝国</color>の首都。セントラルパレス。","ENG":"Central Palace, the capital of the <color=#ffd34c>Empire of Arcadena</color>.","TWN":"<color=#ffd34c>艾爾卡特納帝國</color> 首都 聖特羅貝里斯","SCN":"<color=#ffd34c>阿尔卡德纳帝国</color> 首都，中央宫","DEU":"Central Palace, the capital of the <color=#ffd34c>Empire of Arcadena</color>."},"stage":{"bg":"BLACK","slots":{"L":null,"C":{"char_id":"HOLY_MEMORIAL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};